css:
.sc-kpi-supply {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  --warn: var(--color-warning, #F6C453);
  container-type: inline-size;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  display: flex;
  flex-direction: column;
  gap: 14px;
  padding: 2px;
}
.sc-kpi-supply, .sc-kpi-supply .kpi, .sc-kpi-supply .empty { box-sizing: border-box; }

.sc-kpi-supply .band-head { display: flex; align-items: baseline; gap: 10px; flex-wrap: wrap; }
.sc-kpi-supply .eyebrow {
  display: inline-flex; align-items: center;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em; text-transform: uppercase; color: var(--ink);
}
.sc-kpi-supply .eyebrow .dot {
  width: 7px; height: 7px; border-radius: 50%; margin-right: 8px;
  background: var(--accent);
  box-shadow: 0 0 10px -1px color-mix(in srgb, var(--accent) 70%, transparent);
}
.sc-kpi-supply .sub {
  font: 500 11.5px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
}

.sc-kpi-supply .kpis {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 14px;
}
.sc-kpi-supply .kpi {
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  min-width: 0;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
}
.sc-kpi-supply .kpi .label {
  display: flex; align-items: center;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em; text-transform: uppercase; color: var(--muted);
}
.sc-kpi-supply .kpi .label::before {
  content: ""; display: inline-block; width: 7px; height: 7px; border-radius: 50%;
  margin-right: 8px; background: var(--accent); flex: none;
}
.sc-kpi-supply .kpi .value {
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em; font-variant-numeric: tabular-nums;
  color: var(--ink); margin-top: 8px;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.sc-kpi-supply .kpi .ctx {
  font: 600 11px/1.35 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted); margin-top: 5px;
}

.sc-kpi-supply .kpi.hero {
  border-color: color-mix(in srgb, var(--accent) 38%, var(--line));
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5), 0 0 26px -10px color-mix(in srgb, var(--accent) 60%, transparent);
}
.sc-kpi-supply .kpi.hero .value { color: var(--accent); }

.sc-kpi-supply .kpi.warn .label::before { background: var(--warn); }
.sc-kpi-supply .kpi.warn .value { color: var(--warn); }

.sc-kpi-supply .empty {
  margin: 0; padding: 18px; border: 1px dashed var(--line); border-radius: 14px;
  color: var(--muted); text-align: center;
  font: 600 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

@container (max-width: 1100px) {
  .sc-kpi-supply .kpis { grid-template-columns: repeat(3, minmax(0, 1fr)); }
}
@container (max-width: 640px) {
  .sc-kpi-supply .kpis { grid-template-columns: repeat(2, minmax(0, 1fr)); }
}
@container (max-width: 360px) {
  .sc-kpi-supply .kpis { grid-template-columns: 1fr; }
}
